VALUES
  ('optometrist-moex-00464', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關使用酵素和去蛋白液（enzymeandproteinremovers）來清潔硬式隱形眼鏡，下列敘述何者錯誤？', '["酵素清潔配方被證實可以有效幫助表面活性劑（surfactant）來去除鏡片表面的蛋白", "使用酵素清潔配方未曾被證實會造成硬式隱形眼鏡配戴者的副作用", "和一些錠劑來比，去蛋白液是水狀的，有些可以直接加入保存液中，使用起來很方便", "去蛋白液是利用其強大的還原活性來分解沉積在鏡片上的蛋白"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00465', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於軟式隱形眼鏡的置入（insertion）與取出（removal），下列敘述何者錯誤？', '["置入時，手指最好是乾的，隱形眼鏡才會黏在手指上", "在手指上時，最好先確定隱形眼鏡的正反面是否為對，隱形眼鏡正確的形狀應該要為碟型，若為碗型則 得翻面", "可以用墨西哥捲餅測試（tacotest）來確定鏡片的正反面", "移除隱形眼鏡時，最好用兩手的中指將眼瞼打開。用食指將鏡片從角膜推下至鞏膜，同時要眼睛往上看， 用食指和拇指指腹將鏡片從鞏膜移除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00466', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關軟式隱形眼鏡保養液的敘述，下列何者正確？', '["平常使用多功能保養液（multi-purposesolution,MPS）的人，如果覺得眼乾，改成雙氧保養液（hydrogen peroxide）後無法改善其眼乾的症狀", "多功能保養液比雙氧保養液更不會造成角膜的發炎", "多功能保養液比雙氧保養液更會造成角膜的染色（staining）", "與雙氧保養液比較，較早期的多功能保養液對於棘狀阿米巴原蟲（acanthamoeba）的殺除效果較好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00467', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '驗配硬式隱形眼鏡時，當角膜散光超過多少，需考慮使用後表面散光硬式隱形眼鏡？', '["1.50D", "2.00D", "2.50D", "3.00D"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00468', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '不同的作用力在硬式隱形眼鏡上相互平衡達成理想的驗配，下列敘述何者錯誤？', '["地心引力讓鏡片往下掉", "鏡片後淚液讓鏡片往下掉", "鏡片越大越重越易往下掉", "鏡片重心越往前，鏡片越易往下掉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00469', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '某配戴者鏡框眼鏡處方為-3.00DS/-0.50DC 180，角膜弧度值（keratometryreadings）為41.75D@180/43.00D@90， 如果將基弧為42.00D，度數為-2.00DS的硬式透氣隱形眼鏡配戴至眼睛上時，其預測的戴鏡驗光時的度數 為多少？ ×', '["-0.50DS/-0.75DC 090", "-0.75DS/-1.75DC 180", "-1.00DS/-1.50DC 090", "-1.25DS/-1.00DC 180"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00470', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '下列何種硬式透氧隱×形眼鏡（RGPlens）參數改變，會造成顯著臨床意×義和差異？', '["當基弧（basecurv×eradius）改變0.25D時 ×", "當鏡片直徑（overalldiameter,OAD）改變0.3mm時", "當中央光學區直徑（opticzonediameter,OZD）改變0.4mm時", "當邊弧（peripheralcurveradius）改變0.4mm時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00471', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '高透氧硬式隱形眼鏡使用試片基弧7.60mm/鏡片光學區8.0mm/鏡片直徑9.2mm/度數-3.00DS雙眼 皆能達理想配戴，戴鏡驗光（over-refraction）最佳視力1.0的度數：右眼+4.25DS/-0.50DC 180， 左眼+4.75DS/-0.25DC 180，頂點距離12mm，則下列隱形眼鏡的屈光度數，何者正確？', '["右眼+1.25DS", "左眼+3.00DS", "右眼+3.25DS", "左眼+5.00DS ×"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00472', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '根據Efron第三版，下列×何者不是合適的（well-fitting）軟式鏡片驗配條件？', '["眨眼間鏡片的移動", "鏡片中心定位", "鏡片邊緣需完整覆蓋角膜", "瞳孔大小"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00473', 'optometrist', 'optometrist-moex-113-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '使用螢光染劑來觀察球面硬式隱形眼鏡配戴的情形，下列敘述何者錯誤？', '["主要在觀察鏡片與角膜弧度之間的關係，若觀察到的區域顯示螢光綠，表示鏡片與角膜沒有接觸，若為 黑色，表示鏡片與角膜接觸或者是有大氣泡", "角膜地形圖中，高度圖（Elevationmap）的表現與螢光染色劑在角膜上的分布吻合", "中心區的螢光染色區域愈大，表示鏡片的基弧愈緊（Steep）", "如果角膜散光大於1.0D，螢光染色會呈現啞鈴型，螢光液會堆積在角膜較平的軸線"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:41+00:00", "source_pdf_sha1": "b745f9722863", "answer_pdf_sha1": "cd693ea90406", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
